        long long rootV = find(v);
        if (rootU != rootV) {
            unionSet(rootU, rootV);
            maxHeap.push(w);
        }
    }

    // We need to split the graph into at most k components
    // So we need to remove (total_components - k) edges
    // The maximum cost is the maximum edge weight in the remaining components
    // So we need to find the k-th largest edge weight in the max-heap

    // If k == 1, the answer is the maximum edge weight in the entire graph
    if (k == 1) {
        return maxHeap.top();
    }

    // Remove (total_components - k) edges from the max-heap
    // The answer is the k-th largest edge weight in the max-heap
    long long totalComponents = n - 1; // Initially, the graph is connected
    long long removeCount = totalComponents - k;
    for (long long i = 0; i < removeCount; ++i) {
        maxHeap.pop();
    }

    return maxHeap.top();
}
